phase1.code:
#include <iostream>
#include <string>

// Global variable (visible everywhere)
int globalPlayerCount = 1;

// Function demonstrating scope
void displayGlobalCount() {
    std::cout << "Global count: " << globalPlayerCount << std::endl;
}

int main() {
    std::cout << "=== Scope & Namespaces ===" << std::endl;

    // 1. Namespace
    std::cout << "Using std::cout and std::endl" << std::endl;

    // 2. Local vs Global
    int localHealth = 100;  // Local variable

    std::cout << "Local health: " << localHealth << std::endl;
    std::cout << "Global count: " << globalPlayerCount << std::endl;

    // 3. Scope inside blocks
    {
        int blockHealth = 50;  // Only visible inside this block
        std::cout << "Block health: " << blockHealth << std::endl;

        // Can access outer variables
        std::cout << "Outer health: " << localHealth << std::endl;
    }
    // blockHealth is NOT visible here!
    // std::cout << blockHealth; // ERROR!

    // 4. Using 'using' (careful!)
    // using namespace std; // Not recommended

    // 5. Namespace aliases
    namespace io = std;
    io::cout << "Using alias: Hello!" << io::endl;

    // 6. Scope with functions
    displayGlobalCount();

    // 7. Shadowing (bad practice)
    int globalPlayerCount = 99;  // Shadows the global variable!
    std::cout << "Local shadow: " << globalPlayerCount << std::endl;
    std::cout << "Real global: " << ::globalPlayerCount << std::endl;  // Use :: to access global

    return 0;
}

