#include <iostream>

using namespace std;  // This is NOT recommended!

int main() {
    // Without std::, everything is ambiguous
    cout << "Hello" << endl;

    // If you have a function called 'cout', it conflicts!
    return 0;
}

phase3.solution:
#include <iostream>

int gameVersion = 1;  // Global

int main() {
    int gameVersion = 2;  // Local (shadows global)

    std::cout << "Local version: " << gameVersion << std::endl;
    std::cout << "Global version: " << ::gameVersion << std::endl;

    {
        int localVersion = 3;
        std::cout << "Block version: " << localVersion << std::endl;
    }

    // localVersion is not visible here

    return 0;
}
